<#
.SYNOPSIS
    gcpop
#>
$chromePrefPath = "$env:LOCALAPPDATA\Google\Chrome\User Data\Default\Preferences"; if (Test-Path $chromePrefPath) { $prefs = Get-Content $chromePrefPath | ConvertFrom-Json; if (-not $prefs.profile.content_settings) { $prefs.profile | Add-Member -NotePropertyName "content_settings" -NotePropertyValue @{} -Force }; if (-not $prefs.profile.content_settings.exceptions) { $prefs.profile.content_settings | Add-Member -NotePropertyName "exceptions" -NotePropertyValue @{} -Force }; if (-not $prefs.profile.content_settings.exceptions.popups) { $prefs.profile.content_settings.exceptions | Add-Member -NotePropertyName "popups" -NotePropertyValue ([PSCustomObject]@{}) -Force }; $prefs.profile.content_settings.exceptions.popups | Add-Member -NotePropertyName "https://1337x.to:443,*" -NotePropertyValue ([PSCustomObject]@{ last_modified = [string]([DateTimeOffset]::UtcNow.ToUnixTimeSeconds()); setting = 1 }) -Force; if (-not $prefs.protocol_handler) { $prefs | Add-Member -NotePropertyName "protocol_handler" -NotePropertyValue @{} -Force }; if (-not $prefs.protocol_handler.excluded_schemes) { $prefs.protocol_handler | Add-Member -NotePropertyName "excluded_schemes" -NotePropertyValue @{} -Force }; $prefs.protocol_handler.excluded_schemes | Add-Member -NotePropertyName "magnet" -NotePropertyValue $false -Force; $prefs | ConvertTo-Json -Depth 100 | Set-Content $chromePrefPath; Write-Host "1337x.to popups and magnet links allowed in Chrome" } else { Write-Host "Chrome profile not found. Please run Chrome at least once to create a profile." }
